def guard(features: dict, prediction: str) -> str:
    """Stochastic crossover timing guard - rejects signals with poor k/d alignment."""
    stoch_k = features.get('stoch_k', 50)
    stoch_d = features.get('stoch_d', 50)

    if prediction == 'long':
        if stoch_k <= stoch_d:
            return 'skip'

    if prediction == 'short':
        if stoch_k >= stoch_d:
            return 'skip'

    return prediction
